create table if not exists public.brand_rep_classifications (id uuid primary key default gen_random_uuid(), store_id uuid references public.stores(id), brand text not null, employee_id uuid not null references public.employees(id), active boolean not null default true, note text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique (store_id, brand, employee_id));
insert into public.brand_rep_classifications (store_id, brand, employee_id, active, note) select distinct store_id, brand, employee_id, active, note from public.brand_rep_assignments where active = true on conflict (store_id, brand, employee_id) do update set active = excluded.active, note = excluded.note, updated_at = now();
alter table public.brand_rep_classifications enable row level security;
create policy brand_rep_classifications_select on public.brand_rep_classifications for select to authenticated using (true);
create policy brand_rep_classifications_manage on public.brand_rep_classifications to authenticated using (public.is_admin_or_payroll() or store_id = public.current_store_id()) with check (public.is_admin_or_payroll() or store_id = public.current_store_id());
